CREATE TABLE IF NOT EXISTS raw_items (id uuid PRIMARY KEY DEFAULT gen_random_uuid(), source_type text NOT NULL CHECK (source_type IN ('rss', 'twitter', 'regulatory', 'sec', 'brave_search')), source_name text NOT NULL, source_url text NOT NULL UNIQUE, title text, content text, full_text text, language text DEFAULT 'en', published_at timestamptz NOT NULL, metadata jsonb DEFAULT '{}', processed boolean NOT NULL DEFAULT false, created_at timestamptz NOT NULL DEFAULT now());
